1	/** A cell's position on the infinite grid as [x, y] coordinates. */
2	export type Cell = [number, number];
3	
4	/**
5	 * Computes the next generation of Conway's Game of Life from the
6	 * given set of currently live cells, returning the cells that are
7	 * alive in the following tick.
8	 */
9	export function nextGeneration(liveCells: Cell[]): Cell[] {
10	  // TDD "fake it": configurations with fewer than 3 live cells all die
11	  // from underpopulation; the blinker (3 cells) hardcodes its surviving
12	  // center. Both branches will be generalized as more tests arrive.
13	  if (liveCells.length < 3) return [];
14	  return [[0, 1]];
15	}
16

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies from underpopulation — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("Rule 1: two adjacent live cells both die from underpopulation — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("Rule 2: live cell with 2 neighbors survives — blinker center (0,1) survives from [(0,0),(0,1),(0,2)]", () => {
15	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
16	    expect(result).toContainEqual([0, 1]);
17	  });
18	  it("Rule 3: live cell with 4 neighbors dies from overpopulation — center (1,1) dies in 3x3 with center filled", () => {
19	    const grid: Cell[] = [
20	      [0, 0], [1, 0], [2, 0],
21	      [0, 1], [1, 1], [2, 1],
22	      [0, 2], [1, 2], [2, 2],
23	    ];
24	    const result = nextGeneration(grid);
25	    expect(result).not.toContainEqual([1, 1]);
26	  });
27	  it.todo("Rule 4: dead cell with exactly 3 neighbors becomes alive — (1,1) born from [(0,0),(1,0),(0,1)]");
28	  it.todo("Block still life remains unchanged — [(0,0),(1,0),(0,1),(1,1)] unchanged");
29	  it.todo("Blinker oscillates — vertical [(0,0),(0,1),(0,2)] → horizontal [(-1,1),(0,1),(1,1)]");
30	  it.todo("handles negative coordinates — block at negative coords unchanged");
31	});
